// src/components/FormPaciente.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { format, differenceInYears, parseISO } from 'date-fns';

const EXCEPTION_WORDS = ['de','da','do','dos','das','di','para'];

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const [mensagem, setMensagem] = useState('');

  // campos individuais
  const [numeroProntuario, setNumeroProntuario] = useState('');
  const [numeroGaveta, setNumeroGaveta] = useState('');
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [rg, setRg] = useState('');
  const [cpf, setCpf] = useState('');
  const [dataNascimento, setDataNascimento] = useState('');
  const [idade, setIdade] = useState('');
  const [cep, setCep] = useState('');
  const [endereco, setEndereco] = useState('');
  const [numero, setNumero] = useState('');
  const [cidade, setCidade] = useState('');
  const [observacao, setObservacao] = useState('');

  // carrega edição
  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || '');
      setNumeroGaveta(pacienteEditando.numero_gaveta || '');
      setNome(capitalizeName(pacienteEditando.nome || ''));
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''));
      setRg(pacienteEditando.rg || '');
      setCpf(formatarCPF(pacienteEditando.cpf || ''));
      setDataNascimento(pacienteEditando.data_nascimento || '');
      setIdade(pacienteEditando.idade || '');
      setCep(pacienteEditando.cep || '');
      setEndereco(pacienteEditando.endereco || '');
      setNumero(pacienteEditando.numero || '');
      setCidade(pacienteEditando.cidade || '');
      setObservacao(pacienteEditando.observacao || '');
    } else {
      resetForm();
    }
    setMensagem('');
  }, [pacienteEditando]);

  function resetForm() {
    setNumeroProntuario('');
    setNumeroGaveta('');
    setNome('');
    setTelefone('');
    setRg('');
    setCpf('');
    setDataNascimento('');
    setIdade('');
    setCep('');
    setEndereco('');
    setNumero('');
    setCidade('');
    setObservacao('');
  }

  // formata e valida CPF
  function formatarCPF(value) {
    const v = value.replace(/\D/g, '').slice(0,11);
    return v
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})$/, '$1-$2');
  }
  function validarCPF(value) {
    const nums = value.replace(/\D/g,'');
    if (nums.length !== 11 || /^(\d)\1+$/.test(nums)) return false;
    const calc = (pos) => {
      let sum = 0;
      for (let i=0; i<pos; i++) sum += parseInt(nums.charAt(i)) * (pos+1-i);
      const res = (sum *10) %11; return res===10?0:res;
    };
    return calc(9) === parseInt(nums.charAt(9)) && calc(10) === parseInt(nums.charAt(10));
  }

  // máscara telefone
  function formatarTelefone(campo) {
    const d = campo.replace(/\D/g,'');
    if (d.length <= 2) return d.replace(/^(\d{0,2})/,'($1');
    if (d.length <= 6) return d.replace(/^(\d{2})(\d{0,4})/,'($1) $2');
    return d.replace(/^(\d{2})(\d{5})(\d{0,4}).*/,'($1) $2-$3');
  }

  // capitaliza nome, exceto exceções
  function capitalizeName(str) {
    return str.split(/\s+/).map(w => {
      const lw = w.toLowerCase();
      if (EXCEPTION_WORDS.includes(lw)) return lw;
      return lw.charAt(0).toUpperCase() + lw.slice(1);
    }).join(' ');
  }

  // ao mudar dataNascimento, recalcula idade
  useEffect(() => {
    if (dataNascimento) {
      const yrs = differenceInYears(new Date(), parseISO(dataNascimento));
      setIdade(yrs);
    } else {
      setIdade('');
    }
  }, [dataNascimento]);

  // ao desfocar o CEP, busca ViaCEP
  const handleCepBlur = async () => {
    const clean = cep.replace(/\D/g,'');
    if (clean.length !== 8) return;
    try {
      const { data } = await axios.get(`https://viacep.com.br/ws/${clean}/json/`);
      if (!data.erro) {
        setEndereco(`${data.logradouro} ${data.bairro}`.trim());
        setCidade(data.localidade);
      }
    } catch { /* falhou, ignora */ }
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');

    // validações
    if (!/^[A-Z][a-z]+(?:\s+[A-Z][a-z]+)+$/.test(capitalizeName(nome))) {
      setMensagem('Nome e sobrenome devem iniciar com maiúscula.');
      return;
    }
    const telDig = telefone.replace(/\D/g,'');
    if (![10,11].includes(telDig.length)) {
      setMensagem('Telefone inválido.');
      return;
    }
    if (cpf && !validarCPF(cpf)) {
      setMensagem('CPF inválido.');
      return;
    }

    // monta payload
    const payload = {
      numero_prontuario: numeroProntuario || null,
      numero_gaveta:     numeroGaveta     || null,
      nome:              capitalizeName(nome),
      telefone:          telDig,
      rg:                rg || null,
      cpf:               cpf.replace(/\D/g,'') || null,
      data_nascimento:   dataNascimento || null,
      idade:             idade || null,
      cep:               cep || null,
      endereco:          endereco || null,
      numero:            numero || null,
      cidade:            cidade || null,
      observacao:        observacao || null
    };

    try {
      if (pacienteEditando) {
        await axios.put(`/api/pacientes/${pacienteEditando.id}`, payload);
        setMensagem('Paciente atualizado com sucesso!');
      } else {
        await axios.post('/api/pacientes', payload);
        setMensagem('Paciente cadastrado com sucesso!');
        resetForm();
      }
      onNovoPaciente();
    } catch {
      setMensagem('Erro ao salvar paciente.');
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* 1. Nº Prontuário e Nº Gaveta */}
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Nº Prontuário <small>(opcional)</small>
            </label>
            <input
              type="text" maxLength={8}
              value={numeroProntuario}
              onChange={e => setNumeroProntuario(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Nº Gaveta <small>(opcional)</small>
            </label>
            <input
              type="text"
              value={numeroGaveta}
              onChange={e => setNumeroGaveta(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* 2. Nome e Sobrenome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome e Sobrenome
          </label>
          <input
            type="text" required
            value={nome}
            onChange={e => setNome(e.target.value)}
            onBlur={e => setNome(capitalizeName(e.target.value))}
            className="w-full border rounded px-3 py-2"
            placeholder="Ex: Maria da Silva"
          />
        </div>

        {/* 3. Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
          </label>
          <input
            type="tel" required
            value={telefone}
            onChange={e => setTelefone(formatarTelefone(e.target.value))}
            className="w-full border rounded px-3 py-2"
            placeholder="(XX) XXXXX-XXXX"
          />
        </div>

        {/* 4. RG */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">RG</label>
          <input
            type="text"
            value={rg}
            onChange={e => setRg(e.target.value)}
            className="w-full border rounded px-3 py-2"
          />
        </div>

        {/* 5. CPF */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">CPF</label>
          <input
            type="text"
            value={cpf}
            onChange={e => setCpf(formatarCPF(e.target.value))}
            className="w-full border rounded px-3 py-2"
            placeholder="000.000.000-00"
          />
        </div>

        {/* 6 & 7. Data Nasc. e Idade */}
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Data de Nascimento
            </label>
            <input
              type="date"
              value={dataNascimento}
              onChange={e => setDataNascimento(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">Idade</label>
            <input
              type="number" readOnly
              value={idade}
              className="w-full border rounded px-3 py-2 bg-gray-100"
            />
          </div>
        </div>

        {/* 8. CEP */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">CEP</label>
          <input
            type="text"
            value={cep}
            onChange={e => setCep(e.target.value.replace(/\D/g,'').slice(0,8))}
            onBlur={handleCepBlur}
            className="w-full border rounded px-3 py-2"
            placeholder="00000000"
          />
        </div>

        {/* 9 & 10. Endereço, Número, Cidade */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="md:col-span-2">
            <label className="block mb-2 font-medium text-gray-700">Endereço</label>
            <input
              type="text"
              value={endereco}
              onChange={e => setEndereco(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">Número</label>
            <input
              type="text"
              value={numero}
              onChange={e => setNumero(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">Cidade</label>
            <input
              type="text"
              value={cidade}
              onChange={e => setCidade(e.target.value)}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* 11. Observações */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">Observações</label>
          <textarea
            value={observacao}
            onChange={e => setObservacao(e.target.value)}
            className="w-full border rounded px-3 py-2"
            rows={3}
          />
        </div>

        {/* botões */}
        <div className="flex gap-4">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              onClick={onFimEdicao}
              className="bg-[#DA3648] hover:bg-[#BC3140] text-white font-bold py-2 px-6 rounded-full"
            >
              Cancelar
            </button>
          )}
        </div>

        {/* feedback */}
        {mensagem && (
          <p className="mt-4 text-red-600">{mensagem}</p>
        )}
      </form>
    </div>
  );
}

export default FormPaciente;
